{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Validate and parse the command string to determine the operation to execute",
      "behavior": "Check command is one of 'place', 'cancel', 'track'; return parsed command type",
      "boundary": {
        "in_scope": [
          "command validation",
          "command type extraction"
        ],
        "out_of_scope": [
          "order data validation",
          "execution logic"
        ]
      },
      "semantic_inputs": [
        {
          "name": "command",
          "description": "Order command string",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "command_type",
          "description": "Validated command type",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command is a string"
      ],
      "postconditions": [
        "command_type is 'place', 'cancel', or 'track'"
      ],
      "guarantees": [
        "Returns error if command is invalid"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "ValidateOrderData",
      "purpose": "Validate order_data structure and required fields based on command type",
      "behavior": "Check required fields exist and have correct types; for 'place' ensure items list non-empty; for 'cancel' and 'track' ensure order_id present",
      "boundary": {
        "in_scope": [
          "field presence",
          "type checking",
          "basic format validation"
        ],
        "out_of_scope": [
          "business rule validation",
          "database lookups"
        ]
      },
      "semantic_inputs": [
        {
          "name": "command_type",
          "description": "Parsed command type",
          "source": "ParseCommand output"
        },
        {
          "name": "order_data",
          "description": "Order payload",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "validated_data",
          "description": "Validated order data or error",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command_type is valid"
      ],
      "postconditions": [
        "Returns validated data or raises error"
      ],
      "guarantees": [
        "Ensures data conforms to expected schema"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "PlaceOrder",
      "purpose": "Execute the 'place' order workflow: validate inventory, charge payment, reserve stock, create order, send notification",
      "behavior": "Check item availability and stock, charge payment via payment gateway, reserve inventory, create order record, send confirmation notification; rollback on failure",
      "boundary": {
        "in_scope": [
          "inventory check",
          "payment charge",
          "inventory reservation",
          "order creation",
          "notification"
        ],
        "out_of_scope": [
          "cancel logic",
          "track logic"
        ]
      },
      "semantic_inputs": [
        {
          "name": "validated_data",
          "description": "Validated order data",
          "source": "ValidateOrderData output"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        },
        {
          "name": "inventory",
          "description": "Inventory database",
          "source": "internal leaf access"
        },
        {
          "name": "payments",
          "description": "Payments database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result of place operation",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command_type is 'place'",
        "validated_data is valid"
      ],
      "postconditions": [
        "Order created if successful",
        "Inventory reserved",
        "Payment charged"
      ],
      "guarantees": [
        "Atomic: rollback on failure",
        "Payment charged before stock decrement"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CancelOrder",
      "purpose": "Execute the 'cancel' order workflow: verify order exists and not shipped, refund payment, restore inventory, update order status",
      "behavior": "Lookup order, check status not shipped, refund payment, restore reserved inventory, update order status to cancelled; rollback on failure",
      "boundary": {
        "in_scope": [
          "order lookup",
          "status check",
          "payment refund",
          "inventory restoration",
          "status update"
        ],
        "out_of_scope": [
          "place logic",
          "track logic"
        ]
      },
      "semantic_inputs": [
        {
          "name": "validated_data",
          "description": "Validated order data with order_id",
          "source": "ValidateOrderData output"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        },
        {
          "name": "inventory",
          "description": "Inventory database",
          "source": "internal leaf access"
        },
        {
          "name": "payments",
          "description": "Payments database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result of cancel operation",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command_type is 'cancel'",
        "validated_data is valid"
      ],
      "postconditions": [
        "Order status updated to cancelled",
        "Payment refunded",
        "Inventory restored"
      ],
      "guarantees": [
        "Cannot cancel shipped order",
        "Atomic rollback"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "TrackOrder",
      "purpose": "Execute the 'track' order workflow: return current order status and estimated delivery time",
      "behavior": "Lookup order by order_id, retrieve status and estimated delivery, return result",
      "boundary": {
        "in_scope": [
          "order lookup",
          "status retrieval",
          "delivery time estimation"
        ],
        "out_of_scope": [
          "place logic",
          "cancel logic"
        ]
      },
      "semantic_inputs": [
        {
          "name": "validated_data",
          "description": "Validated order data with order_id",
          "source": "ValidateOrderData output"
        },
        {
          "name": "orders",
          "description": "Order database",
          "source": "internal leaf access"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Result of track operation with status and delivery time",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "command_type is 'track'",
        "validated_data is valid"
      ],
      "postconditions": [
        "Returns order status and estimated delivery"
      ],
      "guarantees": [
        "No side effects on data stores"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "FormatResult",
      "purpose": "Format the operation result into the standard output JSON structure",
      "behavior": "Take success, order_id, status, message from child operation and construct final output dict",
      "boundary": {
        "in_scope": [
          "result formatting",
          "output structure"
        ],
        "out_of_scope": [
          "business logic",
          "data store access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "operation_result",
          "description": "Raw result from PlaceOrder, CancelOrder, or TrackOrder",
          "source": "PlaceOrder | CancelOrder | TrackOrder output"
        }
      ],
      "semantic_outputs": [
        {
          "name": "order_result",
          "description": "Formatted JSON result",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "operation_result is available"
      ],
      "postconditions": [
        "Output conforms to expected JSON schema"
      ],
      "guarantees": [
        "Consistent output format"
      ],
      "composition_role": "aggregate",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The parent OrderSystem is decomposed into a pipeline: first parse command, then validate data, then conditionally execute one of three workflows (place/cancel/track), and finally format the result. This separates concerns: command parsing, data validation, business logic per command, and output formatting.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "ParseCommand",
      "data": "command",
      "note": "Extract command type"
    },
    {
      "from": "ParseCommand",
      "to": "parent",
      "data": "command_type",
      "note": "Pass to parent for routing"
    },
    {
      "from": "parent",
      "to": "ValidateOrderData",
      "data": "command_type, order_data",
      "note": "Validate data based on command"
    },
    {
      "from": "ValidateOrderData",
      "to": "parent",
      "data": "validated_data",
      "note": "Return validated data"
    },
    {
      "from": "parent",
      "to": "PlaceOrder",
      "data": "validated_data",
      "note": "If command is 'place'"
    },
    {
      "from": "parent",
      "to": "CancelOrder",
      "data": "validated_data",
      "note": "If command is 'cancel'"
    },
    {
      "from": "parent",
      "to": "TrackOrder",
      "data": "validated_data",
      "note": "If command is 'track'"
    },
    {
      "from": "PlaceOrder",
      "to": "parent",
      "data": "operation_result",
      "note": "Result from place"
    },
    {
      "from": "CancelOrder",
      "to": "parent",
      "data": "operation_result",
      "note": "Result from cancel"
    },
    {
      "from": "TrackOrder",
      "to": "parent",
      "data": "operation_result",
      "note": "Result from track"
    },
    {
      "from": "parent",
      "to": "FormatResult",
      "data": "operation_result",
      "note": "Format final output"
    },
    {
      "from": "FormatResult",
      "to": "parent",
      "data": "order_result",
      "note": "Final formatted result"
    }
  ]
}
